#include<bits/stdc++.h>
#define ll long long
#define dx(s) transform(s.begin(),s.end(),s.begin(),::tolower)
#define one {printf("-1");return false;}
using namespace std;
string s,s2;int ans=0;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	getline(cin,s);getline(cin,s2);
	dx(s);dx(s2);s2=' '+s2+' ',s=' '+s+' ';
	//cout<<s<<'|'<<s2;
	if(s2.find(s)==string::npos)one
	else{
		for(int i=1;i<s2.size()-1;++i){
			ans+=(s2.substr(i,s.size())==s);
		}printf("%d %d",ans,s2.find(s));
	}
	return false;
}
